```class Solution {
public:
    string reverseVowels(string s) {
        vector<char> vowels;
        for (char c : s) {
            if (c == 'a' || c == 'e' || c == 'i' || c == 'o' || c == 'u') {
                vowels.push_back(c);
            }
        }
        string result = "";
        for (char c : s) {
            if (vowels.count(c) > 0) {
                result += c;
            } else {
                result += string(s.length() - 1, c);
            }
        }
        return result;
    }
};```

